mapper.sql:
c.recycle=0
and (a.id = #{key} or a.name like CONCAT('%',#{key},'%'))
and a.store_id=#{storeId}
and a.starttime   >=   #{startDate}
    and endtime   <=   #{endDate}
 and a.label_id = #{labelId}
 and p.mch_id = #{mchId}

    and a.is_delete = #{is_delete}

mapper.select:
SELECT a.id, a.buylimit, a.discount, a.status, a.goodsName, a.imgurl, a.num, a.goodsPrice, a.attrId, a.className, a.brandName, a.goods_id FROM ( SELECT a.id, a.discount, a.buylimit, a.status, a.goods_id, p.product_title AS goodsName, p.imgurl, p.num, c.price AS goodsPrice, c.id AS attrId, cls.pname className, brand.brand_name brandName, ROW_NUMBER() over(partition by a.id) AS top FROM lkt_flashsale_activity a LEFT JOIN lkt_product_list p ON a.goods_id = p.id LEFT JOIN lkt_mch AS b ON p.mch_id = b.id LEFT JOIN lkt_configure AS c ON p.id = c.pid LEFT JOIN lkt_product_class cls ON cls.cid = substring_index( substring_index( p.product_class, '-', 2 ), '-', - 1 ) LEFT JOIN lkt_brand_class brand ON brand.brand_id = p.brand_id
a.sort ${sort_sort},
) AS a where a.top = 1 limit #{pageNo},#{pageSize}
